fixed_code:
use anyhow::{Result, Context};

fn main() -> Result<()> {
    let mut sum = 0;
    for i in 1..=1000000u64 {
        if let Some(j) = i.try_into().context("Truncation error")? {
            sum += j as u64;
        } else {
            return Err(anyhow::anyhow!("Value too large for u8: {}", i));
        }
    }
    println!("Sum: {}", sum);
    Ok(())
}

